4038 bool InstCombinerImpl::removeInstructionsBeforeUnreachable(Instruction &I) {
4039   // Try to remove the previous instruction if it must lead to unreachable.
4040   // This includes instructions like stores and "llvm.assume" that may not get
4041   // removed by simple dead code elimination.
4042   bool Changed = false;
4043   while (Instruction *Prev = I.getPrevNode()) {
4044     // While we theoretically can erase EH, that would result in a block that
4045     // used to start with an EH no longer starting with EH, which is invalid.
4046     // To make it valid, we'd need to fixup predecessors to no longer refer to
4047     // this block, but that changes CFG, which is not allowed in InstCombine.
4048     if (Prev->isEHPad())
4049       break; // Can not drop any more instructions. We're done here.
4050 
4051     if (!isGuaranteedToTransferExecutionToSuccessor(Prev))
4052       break; // Can not drop any more instructions. We're done here.
4053     // Otherwise, this instruction can be freely erased,
4054     // even if it is not side-effect free.
4055 
4056     // A value may still have uses before we process it here (for example, in
4057     // another unreachable block), so convert those to poison.
4058     replaceInstUsesWith(*Prev, PoisonValue::get(Prev->getType()));
4059     eraseInstFromFunction(*Prev);
4060     Changed = true;
4061   }
4062   return Changed;
4063 }
