4078     BasicBlock::iterator FirstInstr = BBI->getParent()->begin();
4079     do {
4080       if (BBI != FirstInstr)
4081         --BBI;
4082     } while (BBI != FirstInstr && BBI->isDebugOrPseudoInst());
4083 
4084     return dyn_cast<StoreInst>(BBI);
4085   };
4086 
4087   if (StoreInst *SI = GetLastSinkableStore(BasicBlock::iterator(BI)))
4088     if (mergeStoreIntoSuccessor(*SI))
4089       return &BI;
4090 
4091   return nullptr;
4092 }
