4094 void InstCombinerImpl::addDeadEdge(BasicBlock *From, BasicBlock *To,
4095                                    SmallVectorImpl<BasicBlock *> &Worklist) {
4096   if (!DeadEdges.insert({From, To}).second)
4097     return;
4098 
4099   // Replace phi node operands in successor with poison.
4100   for (PHINode &PN : To->phis())
4101     for (Use &U : PN.incoming_values())
4102       if (PN.getIncomingBlock(U) == From && !isa<PoisonValue>(U)) {
4103         replaceUse(U, PoisonValue::get(PN.getType()));
4104         addToWorklist(&PN);
4105         MadeIRChange = true;
4106       }
4107 
4108   Worklist.push_back(To);
4109 }
4110 
4111 // Under the assumption that I is unreachable, remove it and following
4112 // instructions. Changes are reported directly to MadeIRChange.
4113 void InstCombinerImpl::handleUnreachableFrom(
4114     Instruction *I, SmallVectorImpl<BasicBlock *> &Worklist) {
4115   BasicBlock *BB = I->getParent();
4116   for (Instruction &Inst : make_early_inc_range(
4117            make_range(std::next(BB->getTerminator()->getReverseIterator()),
4118                       std::next(I->getReverseIterator())))) {
4119     if (!Inst.use_empty() && !Inst.getType()->isTokenTy()) {
4120       replaceInstUsesWith(Inst, PoisonValue::get(Inst.getType()));
4121       MadeIRChange = true;
4122     }
4123     if (Inst.isEHPad() || Inst.getType()->isTokenTy())
4124       continue;
4125     // RemoveDIs: erase debug-info on this instruction manually.
4126     Inst.dropDbgRecords();
4127     eraseInstFromFunction(Inst);
4128     MadeIRChange = true;
4129   }
4130 
4131   SmallVector<Value *> Changed;
4132   if (handleUnreachableTerminator(BB->getTerminator(), Changed)) {
4133     MadeIRChange = true;
4134     for (Value *V : Changed)
4135       addToWorklist(cast<Instruction>(V));
4136   }
4137 
4138   // Handle potentially dead successors.
4139   for (BasicBlock *Succ : successors(BB))
4140     addDeadEdge(BB, Succ, Worklist);
4141 }
4142 
4143 void InstCombinerImpl::handlePotentiallyDeadBlocks(
4144     SmallVectorImpl<BasicBlock *> &Worklist) {
4145   while (!Worklist.empty()) {
4146     BasicBlock *BB = Worklist.pop_back_val();
4147     if (!all_of(predecessors(BB), [&](BasicBlock *Pred) {
4148           return DeadEdges.contains({Pred, BB}) || DT.dominates(BB, Pred);
4149         }))
4150       continue;
4151 
4152     handleUnreachableFrom(&BB->front(), Worklist);
4153   }
4154 }
4155 
4156 void InstCombinerImpl::handlePotentiallyDeadSuccessors(BasicBlock *BB,
4157                                                        BasicBlock *LiveSucc) {
4158   SmallVector<BasicBlock *> Worklist;
4159   for (BasicBlock *Succ : successors(BB)) {
4160     // The live successor isn't dead.
4161     if (Succ == LiveSucc)
4162       continue;
4163 
4164     addDeadEdge(BB, Succ, Worklist);
4165   }
4166 
4167   handlePotentiallyDeadBlocks(Worklist);
4168 }
