4170 Instruction *InstCombinerImpl::visitBranchInst(BranchInst &BI) {
4171   if (BI.isUnconditional())
4172     return visitUnconditionalBranchInst(BI);
4173 
4174   // Change br (not X), label True, label False to: br X, label False, True
4175   Value *Cond = BI.getCondition();
4176   Value *X;
4177   if (match(Cond, m_Not(m_Value(X))) && !isa<Constant>(X)) {
4178     // Swap Destinations and condition...
4179     BI.swapSuccessors();
4180     if (BPI)
4181       BPI->swapSuccEdgesProbabilities(BI.getParent());
4182     return replaceOperand(BI, 0, X);
4183   }
4184 
4185   // Canonicalize logical-and-with-invert as logical-or-with-invert.
4186   // This is done by inverting the condition and swapping successors:
4187   // br (X && !Y), T, F --> br !(X && !Y), F, T --> br (!X || Y), F, T
4188   Value *Y;
4189   if (isa<SelectInst>(Cond) &&
4190       match(Cond,
4191             m_OneUse(m_LogicalAnd(m_Value(X), m_OneUse(m_Not(m_Value(Y))))))) {
4192     Value *NotX = Builder.CreateNot(X, "not." + X->getName());
4193     Value *Or = Builder.CreateLogicalOr(NotX, Y);
4194     BI.swapSuccessors();
4195     if (BPI)
4196       BPI->swapSuccEdgesProbabilities(BI.getParent());
4197     return replaceOperand(BI, 0, Or);
4198   }
4199 
4200   // If the condition is irrelevant, remove the use so that other
4201   // transforms on the condition become more effective.
4202   if (!isa<ConstantInt>(Cond) && BI.getSuccessor(0) == BI.getSuccessor(1))
4203     return replaceOperand(BI, 0, ConstantInt::getFalse(Cond->getType()));
4204 
4205   // Canonicalize, for example, fcmp_one -> fcmp_oeq.
4206   CmpPredicate Pred;
4207   if (match(Cond, m_OneUse(m_FCmp(Pred, m_Value(), m_Value()))) &&
4208       !isCanonicalPredicate(Pred)) {
4209     // Swap destinations and condition.
4210     auto *Cmp = cast<CmpInst>(Cond);
4211     Cmp->setPredicate(CmpInst::getInversePredicate(Pred));
4212     BI.swapSuccessors();
4213     if (BPI)
4214       BPI->swapSuccEdgesProbabilities(BI.getParent());
4215     Worklist.push(Cmp);
4216     return &BI;
4217   }
4218 
4219   if (isa<UndefValue>(Cond)) {
4220     handlePotentiallyDeadSuccessors(BI.getParent(), /*LiveSucc*/ nullptr);
4221     return nullptr;
4222   }
4223   if (auto *CI = dyn_cast<ConstantInt>(Cond)) {
4224     handlePotentiallyDeadSuccessors(BI.getParent(),
4225                                     BI.getSuccessor(!CI->getZExtValue()));
4226     return nullptr;
4227   }
4228 
4229   // Replace all dominated uses of the condition with true/false
4230   // Ignore constant expressions to avoid iterating over uses on other
4231   // functions.
4232   if (!isa<Constant>(Cond) && BI.getSuccessor(0) != BI.getSuccessor(1)) {
4233     for (auto &U : make_early_inc_range(Cond->uses())) {
4234       BasicBlockEdge Edge0(BI.getParent(), BI.getSuccessor(0));
4235       if (DT.dominates(Edge0, U)) {
4236         replaceUse(U, ConstantInt::getTrue(Cond->getType()));
4237         addToWorklist(cast<Instruction>(U.getUser()));
4238         continue;
4239       }
4240       BasicBlockEdge Edge1(BI.getParent(), BI.getSuccessor(1));
4241       if (DT.dominates(Edge1, U)) {
4242         replaceUse(U, ConstantInt::getFalse(Cond->getType()));
4243         addToWorklist(cast<Instruction>(U.getUser()));
4244       }
4245     }
4246   }
4247 
4248   DC.registerBranch(&BI);
4249   return nullptr;
